dmgFloat(x,y,dmg,head){                                   // 伤害数字:抛物上扬+轻微旋转+淡出
  const showDmg=dmg>=1?Math.round(dmg):(Math.round(dmg*10)/10);
  const txt=this.add.text(x,y,'-'+showDmg,{ fontFamily:'"Black Ops One"', fontSize:head?'28px':'19px', color:head?'#ffd24a':'#ffe9c8' }).setOrigin(0.5).setDepth(86);
  txt.setShadow(0,2,'rgba(0,0,0,0.85)',4);
  if(head)txt.setScale(0.4); else txt.setScale(0.6);
  this.tweens.add({ targets:txt, scale:head?1.05:0.85, duration:120, ease:'Back.easeOut' });
  this.tweens.add({ targets:txt, x:x+rnd(-30,30), y:y-rnd(58,82), angle:rnd(-12,12), alpha:0, duration:head?780:620, ease:'Cubic.easeOut', onComplete:()=>txt.destroy() });

