drawReloadRing(progress){                                 // progress 0..1
  const g=this.reloadRing; g.clear();
  const cx=DW/2, cy=DH-100, R=28;
  g.lineStyle(4, 0x1a0d0c, 0.85); g.strokeCircle(cx,cy,R);                  // 底环
  g.lineStyle(4, 0xd8b15a, 0.95);
  g.beginPath(); g.arc(cx,cy,R, -Math.PI/2, -Math.PI/2 + Math.PI*2*progress, false); g.strokePath();  // 进度环
  g.fillStyle(0xd8b15a, 0.18); g.fillCircle(cx,cy,R-4);                     // 内圆微填
  // tick 刻度
  for(let i=0;i<8;i++){ const a=-Math.PI/2 + i*Math.PI/4; const x1=cx+Math.cos(a)*(R+3), y1=cy+Math.sin(a)*(R+3), x2=cx+Math.cos(a)*(R+7), y2=cy+Math.sin(a)*(R+7); g.lineStyle(1.5, 0xd8b15a, 0.5).lineBetween(x1,y1,x2,y2); }

syncHUD(){
  this.hudScore.setText(String(this.score).padStart(5,'0'));
  this.hudWave.setText('第 '+this.level+' 关 · '+this.waveInLevel+'/'+this.wavesForLevel(this.level)+' 波');
  this.hudCombo.setText(this.combo>1?('连杀 ×'+this.combo):'');
  const hp=this.bunkerHP/this.maxHP;
  this.hpFill.width=256*hp; this.hpFill.fillColor = hp>.5?0x5fae6a:hp>.25?0xd8b15a:0xc23a3a;
  this.hudAmmo.setText(this.reloading?'换弹…':(this.ammo+' / '+this.clip));
  this.hudAmmo.setColor(this.reloading?'#d8b15a':(this.ammo<=20?'#c23a3a':'#e7e6df'));
  if(this.ammoFill){ this.ammoFill.width=206*(this.ammo/this.clip); this.ammoFill.fillColor=this.reloading?0x5b6b6e:(this.ammo<=20?0xc23a3a:0xd8b15a); }
  // —— Reload 圆环 ——
  if(this.reloadRing){
    if(this.reloading){ const p=1 - (this.reloadT/this.reloadDur); this.reloadRing.setVisible(true); this.reloadRingTxt.setVisible(true); this.drawReloadRing(p); }
    else { this.reloadRing.setVisible(false); this.reloadRingTxt.setVisible(false); }
  }
  // —— 关卡进度条更新 ——
  if(this.levelBarFill){ const total=this.wavesForLevel(this.level); const p=clamp(this.waveInLevel/total,0,1); this.levelBarFill.width = (DW-40)*p; this.levelBarTxt.setText('LEVEL '+this.level+' · '+this.waveInLevel+' / '+total); }
  // —— Damage Boost 倒计时角标 ——
  if(this.boostTimer>0 && this.boostBadge){ this.boostBadge.setVisible(true); this.boostBadgeTxt.setText('×2  '+this.boostTimer.toFixed(1)+'s'); const pulse=0.85+0.15*Math.sin(this.time.now/80); this.boostBadge.setAlpha(pulse); }
  else if(this.boostBadge){ this.boostBadge.setVisible(false); }
