comboPulse(level){                                          // 屏边红色脉冲:level 越高越亮越多次
  if(!this.comboEdge){
    this.comboEdge=this.add.graphics().setDepth(73).setBlendMode('ADD');
    this.comboEdge.fillStyle(0xff2a2a, 1);
    this.comboEdge.fillRect(0,0,DW,90);                     // 上带
    this.comboEdge.fillRect(0,DH-90,DW,90);                 // 下带
    this.comboEdge.fillRect(0,0,80,DH);                     // 左带
    this.comboEdge.fillRect(DW-80,0,80,DH);                 // 右带
    // 渐变 mask:用 createCanvas 画一个软边长方形
    this.comboEdge.setAlpha(0);
  }
  const peak = Math.min(0.55, 0.22 + level*0.022);          // 5→0.33, 10→0.44, 15→0.55
  const reps = level>=15?3 : level>=10?2 : 1;
  this.tweens.killTweensOf(this.comboEdge);
  this.tweens.add({ targets:this.comboEdge, alpha:peak, duration:120, yoyo:true, repeat:reps, ease:'Sine.easeOut', onComplete:()=>this.comboEdge.setAlpha(0) });
  // 颜色随等级:5 暖橙 / 10 血红 / 15 紫红
  this.comboEdge.clear();
  const col = level>=15?0xff1a4a : level>=10?0xff2a2a : 0xff6a2a;
  this.comboEdge.fillStyle(col,1);
  this.comboEdge.fillRect(0,0,DW,90); this.comboEdge.fillRect(0,DH-90,DW,90);
  this.comboEdge.fillRect(0,0,80,DH); this.comboEdge.fillRect(DW-80,0,80,DH);
  AudioFX.wave();
